// Simulate complete workflow data
const fullData = {
  monthDay: '8/27',
  dayOfWeek: 'Wednesday',
  today: 'Wednesday, August 27, 2025',
  theme: 'Listening',
  saint: {
    name: 'Monica',
    intro: 'Mother of St. Augustine, she prayed for her son\'s conversion for many years.'
  },
  readings: {
    firstReading: '1 Thessalonians 2:9-13',
    psalm: 'Psalm 139:7-8, 9-10, 11-12ab',
    gospel: 'Matthew 23:27-32',
    usccbLink: 'https://bible.usccb.org/bible/readings/082725.cfm'
  }
};

console.log('Workflow data going to AI:', JSON.stringify(fullData, null, 2));
return [fullData];

// Simulate AI response (what the AI node actually outputs)
const inputData = $json;

console.log('AI received data:', JSON.stringify(inputData, null, 2));

// This is what the AI node returns - ONLY the AI generated content
const aiResponse = {
  text: JSON.stringify({
    reflection: 'Today\'s theme of Listening calls us to cultivate the Benedictine virtue of attentive presence, just as Monica listened deeply to God\'s will for her son Augustine.',
    challenge: 'Practice lectio divina with today\'s first reading. Set aside 15 minutes to truly listen - to Scripture, to God, and to those around you.',
    prayer: 'Lord, help us listen as Monica listened - with patience, faith, and unwavering hope. Guide us to hear your voice in Scripture and in the quiet moments of this day. Amen.'
  })
};

console.log('AI returning:', JSON.stringify(aiResponse, null, 2));
return [aiResponse];

// Data Merger - TEST SOLUTION
const aiResponse = $json; // AI output (only has 'text' field)
const allInputs = $input.all(); // Get all previous data

console.log('=== DATA MERGER DEBUG ===');
console.log('AI response:', JSON.stringify(aiResponse, null, 2));
console.log('Number of inputs:', allInputs.length);
allInputs.forEach((input, i) => {
  console.log(`Input ${i}:`, Object.keys(input.json || {}));
});

// Find the workflow data (should be input 0)
let workflowData = {};
if (allInputs.length > 0) {
  workflowData = allInputs[0]?.json || {};
  console.log('✅ Found workflow data with keys:', Object.keys(workflowData));
  console.log('✅ Has readings:', !!workflowData.readings);
  if (workflowData.readings) {
    console.log('✅ First Reading:', workflowData.readings.firstReading);
  }
} else {
  console.log('❌ No workflow data found in inputs');
}

// Parse AI response
let aiContent = {};
try {
  const aiText = aiResponse?.text || '';
  if (aiText) {
    aiContent = JSON.parse(aiText);
    console.log('✅ Parsed AI content successfully');
    console.log('✅ AI reflection:', aiContent.reflection?.substring(0, 50) + '...');
  }
} catch (parseError) {
  console.log('❌ AI parse error:', parseError.message);
  aiContent = {
    reflection: 'Fallback reflection for debugging.',
    challenge: 'Fallback challenge.',
    prayer: 'Fallback prayer. Amen.'
  };
}

// Combine everything
const mergedData = {
  ...workflowData,  // All the original data (date, saint, readings)
  ai: aiContent     // Add AI content under 'ai' key
};

console.log('✅ Data merger complete. Final keys:', Object.keys(mergedData));
console.log('✅ Final has readings:', !!mergedData.readings);
console.log('✅ Final has AI:', !!mergedData.ai);

if (mergedData.readings) {
  console.log('✅ Final first reading:', mergedData.readings.firstReading);
}
if (mergedData.ai) {
  console.log('✅ Final AI reflection:', mergedData.ai.reflection?.substring(0, 50) + '...');
}

return [mergedData];

// Test final email output
const allData = $json;

console.log('=== EMAIL COMPILER TEST ===');
console.log('Data keys:', Object.keys(allData));
console.log('Has readings:', !!allData.readings);
console.log('Has AI:', !!allData.ai);

// Test readings extraction
if (allData.readings) {
  console.log('✅ First Reading found:', allData.readings.firstReading);
  console.log('✅ Gospel found:', allData.readings.gospel);
} else {
  console.log('❌ No readings in final data');
}

// Test AI extraction
if (allData.ai) {
  console.log('✅ AI reflection found:', allData.ai.reflection?.substring(0, 50) + '...');
  console.log('✅ AI challenge found:', allData.ai.challenge?.substring(0, 50) + '...');
} else {
  console.log('❌ No AI data in final data');
}

// Create simplified email
const subject = `Daily Summary Test - ${allData.today}`;
const body = `
DAILY SUMMARY - ${allData.today}
Theme: ${allData.theme}

Saint: ${allData.saint?.name}
${allData.saint?.intro}

READINGS:
First Reading: ${allData.readings?.firstReading || 'MISSING'}
Psalm: ${allData.readings?.psalm || 'MISSING'}
Gospel: ${allData.readings?.gospel || 'MISSING'}

REFLECTION:
${allData.ai?.reflection || 'MISSING'}

CHALLENGE:
${allData.ai?.challenge || 'MISSING'}

PRAYER:
${allData.ai?.prayer || 'MISSING'}

---
Data Flow Test Complete
`;

console.log('✅ Email generated successfully');
console.log('Subject:', subject);

return [{
  subject: subject,
  body: body,
  testResults: {
    hasReadings: !!allData.readings,
    hasAI: !!allData.ai,
    readingsFirstReading: allData.readings?.firstReading,
    aiReflection: allData.ai?.reflection?.substring(0, 100)
  }
}];
